module top_module(
    input  VPWR,
    input  UDP_IN,
    input  CLK,
    output UDP_OUT
);reg pwrgood;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
        if (UDP_IN) begin
            pwrgood <= 0;
        end else begin
            pwrgood <= VPWR;
        end
    end

    assign UDP_OUT = pwrgood;

endmodule
